body:
Consider the following FIRRTL dialect MLIR:

``` mlir
module {
  firrtl.circuit "Foo" {
    firrtl.layer @A bind {
      firrtl.layer @B bind {
      }
    }
    firrtl.module @Foo(in %clk: !firrtl.clock, in %a: !firrtl.uint<1>, out %b: !firrtl.uint<1>, out %c: !firrtl.uint<1>, out %d: !firrtl.uint<1>, out %e: !firrtl.uint<0>, out %f: !firrtl.uint<4>, out %g: !firrtl.uint<1>, out %h: !firrtl.uint<1>, out %i: !firrtl.uint<1>) attributes {convention = #firrtl<convention scalarized>} {
      %c0_ui0 = firrtl.constant 0 : !firrtl.uint<0>
      %c0_ui4 = firrtl.constant 0 : !firrtl.uint<4>
      %c0_ui1 = firrtl.constant 0 : !firrtl.uint<1>
      %c1_ui1 = firrtl.constant 1 : !firrtl.uint<1>
      %c0_ui1_0 = firrtl.constant 0 : !firrtl.const.uint<1>
      firrtl.matchingconnect %b, %c0_ui1 : !firrtl.uint<1>
      firrtl.matchingconnect %g, %c0_ui1 : !firrtl.uint<1>
      firrtl.matchingconnect %h, %c0_ui1 : !firrtl.uint<1>
      firrtl.matchingconnect %i, %c0_ui1 : !firrtl.uint<1>
      firrtl.layerblock @A {
        firrtl.layerblock @A::@B {
          %reg = firrtl.regreset %clk, %a, %c0_ui1_0 : !firrtl.clock, !firrtl.uint<1>, !firrtl.const.uint<1>, !firrtl.uint<1>
          %_io_deq_T_26 = firrtl.eq %reg, %c0_ui1_0 : (!firrtl.uint<1>, !firrtl.const.uint<1>) -> !firrtl.uint<1>
          %reg_1 = firrtl.regreset %clk, %a, %c0_ui1_0 : !firrtl.clock, !firrtl.uint<1>, !firrtl.const.uint<1>, !firrtl.uint<1>
          %0 = firrtl.int.ltl.implication %reg_1, %_io_deq_T_26 : (!firrtl.uint<1>, !firrtl.uint<1>) -> !firrtl.uint<1>
          firrtl.int.verif.assert %0, %c1_ui1 : !firrtl.uint<1>, !firrtl.uint<1>
        }
      }
      firrtl.matchingconnect %c, %c0_ui1 : !firrtl.uint<1>
      firrtl.matchingconnect %d, %c0_ui1 : !firrtl.uint<1>
      firrtl.matchingconnect %e, %c0_ui0 : !firrtl.uint<0>
      firrtl.matchingconnect %f, %c0_ui4 : !firrtl.uint<4>
    }
  }
}
```

When compiled, this produced a vacuously true implication: `1'h0 |-> 1'h1`. (This is true in both the antecedent and the consequent.) This is the output:

``` verilog
module Foo_A_B();	// reduced.mlir:18:9
  wire _GEN = 1'h0;	// reduced.mlir:23:11
  assert property (disable iff (_GEN) _GEN |-> 1'h1);	// reduced.mlir:22:16, :23:11
endmodule
```

The problem is likely due to CSE related to the use inside and outside the layer block.
